module RefModule(
    input A1,
    input A2,
    input B1,
    input B2,
    output Y
  wire temp1_(A1 & A2) | ((A1 & ~B1 & ~B2) & ~(A2 | B1 | B2)) = (A1 & A2) | ((A1 & ~B1 & ~B2) & ~(A2 | B1 | B2));
  wire temp2_(~A1 & ~A2 & B1 & B2) = (~A1 & ~A2 & B1 & B2);
  assign Y = temp1_(A1 & A2) | ((A1 & ~B1 & ~B2) & ~(A2 | B1 | B2)) | temp2_(~A1 & ~A2 & B1 & B2);

endmodule
